function solve(grid: number[][], k: number): number {
  const m = grid.length;
  const n = grid[0].length;

  const INF = Number.MAX_VALUE;
  const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(INF)));
  dist[0][0][0] = 0;

  class PriorityQueue {
    private heap: [number, number, number, number][] = [];
    private size: number = 0;

    push(cost: number, i: number, j: number, t: number): void {
      this.heap.push([cost, i, j, t]);
      this.size++;
      this.siftUp(this.size - 1);
    }

    pop(): [number, number, number, number] | null {
      if (this.size === 0) return null;
      const val = this.heap[0];
      this.heap[0] = this.heap[this.size - 1];
      this.size--;
      this.siftDown(0);
      return val;
    }

    private siftUp(index: number): void {
      while (index > 0) {
        const parent = (index - 1) >> 1;
        if (this.heap[index][0] >= this.heap[parent][0]) {
          [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
          index = parent;
        } else {
          break;
        }
      }
    }

    private siftDown(index: number): void {
      const length = this.size;
      while (index < length) {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let smallest = index;
        if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
          smallest = left;
        }
        if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
          smallest = right;
        }
        if (smallest !== index) {
          [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
          index = smallest;
        } else {
          break;
        }
      }
    }

    isEmpty(): boolean {
      return this.size === 0;
    }
  }

  const pq = new PriorityQueue();
  pq.push(0, 0, 0, 0);

  while (!pq.isEmpty()) {
    const [cost, i, j, t] = pq.pop()!;
    if (i === m - 1 && j === n - 1) {
      return cost;
    }
    if (cost > dist[i][j][t]) {
      continue;
    }

    const directions = [[0, 1], [1, 0]];
    for (const [di, dj] of directions) {
      const ni = i + di;
      const nj = j + dj;
      if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
        const newCost = cost + grid[ni][nj];
        if (newCost < dist[ni][nj][t]) {
          dist[ni][nj][t] = newCost;
          pq.push(newCost, ni, nj, t);
        }
      }
    }

    if (t < k) {
      for (let x = 0; x < m; x++) {
        for (let y = 0; y < n; y++) {
          if (grid[x][y] <= grid[i][j]) {
            const newCost = cost;
            if (newCost < dist[x][y][t + 1]) {
              dist[x][y][t + 1] = newCost;
              pq.push(newCost, x, y, t + 1);
            }
          }
        }
      }
    }
  }

  return -1;
}

