import (
	"container/heap"
)

func solve(grid [][]int64, k int64) int64 {
	m := len(grid)
	n := len(grid[0])

	const INF = 1 << 60
	dist := make([][][]int64, m)
	for i := 0; i < m; i++ {
		dist[i] = make([][]int64, n)
		for j := 0; j < n; j++ {
			dist[i][j] = make([]int64, k+1)
			for t := 0; t <= int(k); t++ {
				dist[i][j][t] = INF
			}
		}
	}
	dist[0][0][0] = 0

	type pqItem struct {
		cost int64
		i    int
		j    int
		t    int
	}

	type PriorityQueue []*pqItem

	func (pq PriorityQueue) Len() int { return len(pq) }
	func (pq PriorityQueue) Less(i, j int) bool { return pq[i].cost < pq[j].cost }
	func (pq PriorityQueue) Swap(i, j int) {
		pq[i], pq[j] = pq[j], pq[i]
	}

	func (pq *PriorityQueue) Push(x interface{}) {
		item := x.(*pqItem)
		*pq = append(*pq, item)
	}

	func (pq *PriorityQueue) Pop() interface{} {
		old := *pq
		n := len(old)
		item := old[n-1]
		*pq = old[0 : n-1]
		return item
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &pqItem{cost: 0, i: 0, j: 0, t: 0})

	directions := [][2]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*pqItem)
		cost := current.cost
		i := current.i
		j := current.j
		t := current.t

		if i == m-1 && j == n-1 {
			return cost
		}

		if cost > dist[i][j][t] {
			continue
		}

		for _, dir := range directions {
			ni := i + dir[0]
			nj := j + dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := cost + grid[ni][nj]
				if newCost < dist[ni][nj][t] {
					dist[ni][nj][t] = newCost
					heap.Push(&pq, &pqItem{cost: newCost, i: ni, j: nj, t: t})
				}
			}
		}

		if t < int(k) {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if grid[x][y] <= grid[i][j] {
						newCost := cost
						if newCost < dist[x][y][t+1] {
							dist[x][y][t+1] = newCost
							heap.Push(&pq, &pqItem{cost: newCost, i: x, j: y, t: t + 1})
						}
					}
				}
			}
		}
	}

	return -1
}
