	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &State{cost: 0, i: 0, j: 0, t: 0})

	directions := [][2]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*State)
		cost := current.cost
		i := current.i
		j := current.j
		t := current.t

		if i == m-1 && j == n-1 {
			return cost
		}

		if cost > dist[i][j][t] {
			continue
		}

		// Regular moves
		for _, dir := range directions {
			ni := i + dir[0]
			nj := j + dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				newCost := cost + grid[ni][nj]
				if newCost < dist[ni][nj][t] {
					dist[ni][nj][t] = newCost
					heap.Push(&pq, &State{cost: newCost, i: ni, j: nj, t: t})
